var raw = $input.first().json;
var body = raw.body || raw;
var data = body.data || body;
var tenantId = String(body.tenantId || data.tenantId || '');

function esc(v) {
  return v == null ? '' : String(v).replace(/'/g, "''");
}

const uuidRegex = /^[0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12}$/i;
if (!uuidRegex.test(tenantId)) {
  throw new Error('Invalid tenantId');
}

var tid = esc(tenantId);
var query = "SELECT " +
  // Effectif
  "(SELECT COUNT(*) FROM equipe_members WHERE tenant_id = '" + tid + "' AND actif = true) as effectif_total, " +
  "(SELECT COUNT(*) FROM equipe_members WHERE tenant_id = '" + tid + "' AND actif = true AND contrat_type = 'CDI') as effectif_cdi, " +
  "(SELECT COUNT(*) FROM equipe_members WHERE tenant_id = '" + tid + "' AND actif = true AND contrat_type = 'CDD') as effectif_cdd, " +
  // Contrats
  "(SELECT COUNT(*) FROM rh_contrats WHERE tenant_id = '" + tid + "' AND statut = 'actif') as contrats_actifs, " +
  "(SELECT COUNT(*) FROM rh_contrats WHERE tenant_id = '" + tid + "' AND date_fin IS NOT NULL AND date_fin <= NOW() + INTERVAL '30 days' AND date_fin >= NOW() AND statut = 'actif') as contrats_expirant_30j, " +
  // Congés
  "(SELECT COUNT(*) FROM rh_conges WHERE tenant_id = '" + tid + "' AND statut = 'en_attente') as conges_en_attente, " +
  "(SELECT COUNT(*) FROM rh_conges WHERE tenant_id = '" + tid + "' AND statut = 'approuve' AND date_debut <= NOW() AND date_fin >= NOW()) as conges_en_cours, " +
  // Formations
  "(SELECT COUNT(*) FROM rh_formations WHERE tenant_id = '" + tid + "' AND statut = 'en_cours') as formations_en_cours, " +
  "(SELECT COUNT(*) FROM rh_formations WHERE tenant_id = '" + tid + "' AND statut = 'planifiee') as formations_planifiees, " +
  "(SELECT COUNT(*) FROM rh_inscriptions_formations WHERE tenant_id = '" + tid + "') as total_inscriptions_formations, " +
  // Évaluations
  "(SELECT COUNT(*) FROM rh_evaluations WHERE tenant_id = '" + tid + "' AND DATE_TRUNC('month', created_at) = DATE_TRUNC('month', NOW())) as evaluations_ce_mois, " +
  "(SELECT COALESCE(AVG(note_globale), 0) FROM rh_evaluations WHERE tenant_id = '" + tid + "' AND annee = EXTRACT(YEAR FROM NOW())) as note_moyenne_annee, " +
  // Entretiens
  "(SELECT COUNT(*) FROM rh_entretiens WHERE tenant_id = '" + tid + "' AND statut = 'planifie' AND date_entretien >= NOW()) as entretiens_planifies, " +
  // Documents
  "(SELECT COUNT(*) FROM rh_documents WHERE tenant_id = '" + tid + "') as total_documents, " +
  // Bulletins
  "(SELECT COUNT(*) FROM rh_bulletins_paie WHERE tenant_id = '" + tid + "' AND mois = EXTRACT(MONTH FROM NOW()) AND annee = EXTRACT(YEAR FROM NOW())) as bulletins_mois_courant, " +
  // Masse salariale
  "(SELECT COALESCE(SUM(salaire_base), 0) FROM rh_contrats WHERE tenant_id = '" + tid + "' AND statut = 'actif') as masse_salariale, " +
  // Taux d'absentéisme
  "(SELECT COALESCE(COUNT(*) FILTER (WHERE statut = 'approuve' AND date_debut <= NOW() AND date_fin >= NOW()) * 100.0 / NULLIF((SELECT COUNT(*) FROM equipe_members WHERE tenant_id = '" + tid + "' AND actif = true), 0), 0) FROM rh_conges WHERE tenant_id = '" + tid + "') as taux_absenteisme";

return [{json: {query: query}}];

var r = $input.first().json;
var result = {
  effectif: {
    total: Number(r.effectif_total || 0),
    cdi: Number(r.effectif_cdi || 0),
    cdd: Number(r.effectif_cdd || 0)
  },
  contrats: {
    actifs: Number(r.contrats_actifs || 0),
    expirant30j: Number(r.contrats_expirant_30j || 0)
  },
  conges: {
    enAttente: Number(r.conges_en_attente || 0),
    enCours: Number(r.conges_en_cours || 0)
  },
  formations: {
    enCours: Number(r.formations_en_cours || 0),
    planifiees: Number(r.formations_planifiees || 0),
    totalInscriptions: Number(r.total_inscriptions_formations || 0)
  },
  evaluations: {
    ceMois: Number(r.evaluations_ce_mois || 0),
    noteMoyenneAnnee: Math.round(Number(r.note_moyenne_annee || 0) * 100) / 100
  },
  entretiens: {
    planifies: Number(r.entretiens_planifies || 0)
  },
  documents: {
    total: Number(r.total_documents || 0)
  },
  paie: {
    bulletinsMoisCourant: Number(r.bulletins_mois_courant || 0),
    masseSalariale: Number(r.masse_salariale || 0)
  },
  tauxAbsenteisme: Math.round(Number(r.taux_absenteisme || 0) * 100) / 100
};
return [{json: {success: true, data: result}}];
